+        console.log(`${chalk.white("Description:")} ${checkpoint.description}`);
+        console.log(`${chalk.white('Created:')} ${new Date(checkpoint.timestamp).toLocaleString()}`);
+        console.log();
+        console.log(chalk.cyan.bold('Statistics'));
