      return JSON.parse(content);
    } catch (error) {
      return [];
    }
  }

  async getPerformanceMetrics(): Promise<PerformanceMetrics | null> {
    try {
      const filePath = path.join(this.metricsDir, 'performance.json');
      const content = await fs.readFile(filePath, 'utf8');
      return JSON.parse(content);
    } catch (error) {
      return null;
    }
  }

